#include <stdio.h>

int main() {
    int n;
    scanf("%d", &n);

    int a[n];

    // taking input 
    for (int i = 0; i < n; i++) {
        scanf("%d", &a[i]);
    }

    // printing elements of the array
    for (int i = 0; i < n; i++) {
        printf("%d ", a[i]);
    }

    return 0;
}
